PROC SQL &lt;<i>options</i>&gt;;
	ALTER TABLE <i>table-name</i>
		&lt;ADD <i>column-definition-1</i>&lt;,                               <i>column-definition-2</i>,                             ...&gt;&gt;
		&lt;ADD <i>constraint-specification-1</i>&lt;,                               <i>constraint-specification-2</i>,                             ...&gt;&gt;
		&lt;ADD CONSTRAINT <i>constraint-name-1</i><i>constraint-specification-1</i>
			&lt;,                               <i>constraint-name-2</i>
                           <i>constraint-specification-2</i>,                             ...&gt;&gt;
		&lt;DROP <i>column-1</i>&lt;,                               <i>column-2</i>,                             ...&gt;&gt;
		&lt;DROP CONSTRAINT <i>constraint-name-1</i>&lt;,                               <i>constraint-name-2</i>,                             ...&gt;&gt;
		&lt;DROP FOREIGN KEY <i>constraint-name</i>&gt;
		&lt;DROP PRIMARY KEY &gt;
		&lt;MODIFY <i>column-definition-1</i>&lt;,                               <i>column-definition-2</i>,                             ...&gt;&gt;                                                                                                                 ;

	CREATE &lt;UNIQUE &gt;INDEX <i>index-name</i>
		ON <i>table-name</i> (<i>column-1</i>
                  &lt;, <i>column-2</i>,                          ...&gt;);

	CREATE TABLE <i>table-name</i>
		(<i>column-specification-1</i>&lt;, <i>column-specification-2</i> 
		| <i>constraint-specification-1</i>,                       ...&gt;);

	CREATE TABLE  <i>table-name</i>LIKE <i>table-name-2</i> ;

	CREATE TABLE <i>table-name</i>AS <i>query-expression</i>
		&lt;ORDER BY <i>order-by-item-1</i>&lt;,                               <i>order-by-item-2</i>,                             ...&gt;&gt;;

	CREATE VIEW <i>proc-sql-view</i>
		&lt;(<i>column-name-list</i>)&gt;AS <i>query-expression</i>
		&lt;ORDER                         BY <i>order-by-item-1</i>&lt;,                               <i>order-by-item-2</i>,                             ...&gt;&gt;
		&lt;USING <i>libname-clause-1</i>&lt;,                               <i>libname-clause-2</i>,                             ...&gt;&gt; ;

	DELETE FROM <i>table-name                      </i> | <i>sas/access-view</i> |  <i>proc-sql-view</i>
		&lt;AS <i>alias</i>&gt;
		&lt;WHERE <i>sql-expression</i>&gt;;

	DESCRIBE TABLE                    <i>table-name-1</i> &lt;, <i>table-name-2</i> ,                       ...&gt;;

	DESCRIBE VIEW <i>proc-sql-view-1</i> &lt;, <i>proc-sql-view-2</i> ,                       ...&gt;;

	DESCRIBE TABLE CONSTRAINTS <i>table-name-1</i>&lt;, <i>table-name-2</i>,                       ...&gt;;

	DROP INDEX                    <i>index-name-1</i>&lt;, <i>index-name-2</i>,                       ...&gt;FROM <i>table-name</i>;

	DROP TABLE <i>table-name-1</i> &lt;, <i>table-name-2</i> ,                       ...&gt;;

	DROP VIEW <i>view-name-1</i>&lt;, <i>view-name-2</i>  ,                       ...&gt;;

	INSERT INTO <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>
		&lt;(<i>column-1</i>&lt;, <i>column-2</i>,                             ...&gt;)&gt;
		SET <i>column1=</i><i>sql-expression-1</i>&lt;, <i>column-2=</i><i>sql-expression-2</i>,                          ...&gt;
			&lt;<i>column1=</i><i>sql-expression-1</i>&lt;, <i>column-2=</i><i>sql-expression-2</i>,                                ...&gt; ...&gt;;

	INSERT INTO <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>
		&lt;(<i>column-1</i>
                     &lt;, <i>column-2</i>,                             ...&gt;)&gt;
		VALUES  (<i>value-1</i>&lt;, <i>value-2</i>,                          ...&gt;                   ) 
			&lt;VALUES  (<i>value-1</i>&lt;, <i>value-2</i>,                                ...&gt;                         ) &gt;;

	INSERT INTO <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>
		&lt;(<i>column-1</i>
                     &lt;, <i>column-2</i>,                             ...&gt;)&gt;
		<i>query-expression</i>;

	RESET &lt;<i>options</i>&gt;;

	SELECT &lt;DISTINCT | UNIQUE&gt;<i>object-item-1</i>&lt;, <i>object-item-2</i>,                       ...&gt;

			&lt;INTO <i>macro-variable-specification-1</i>&lt;, <i>macro-variable-specification-2</i>,                                ...&gt;&gt;
			FROM <i>from-list</i>
			&lt;WHERE <i>sql-expression</i>&gt;
			&lt;GROUP                            BY <i>group-by-item-1</i>&lt;, <i>group-by-item-2</i>,  ...&gt;&gt;
			&lt;HAVING <i>sql-expression</i>&gt;
			&lt;ORDER                            BY <i>order-by-item-1</i>&lt;, <i>                                  order-by-item-2</i>
                              &lt;ASC | DESC&gt;,  ...&gt;&gt;;

	UPDATE <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>&lt;AS <i>alias</i>&gt;
		SET <i>column-1</i>=<i>sql-expression-1</i>&lt;, <i>column-2</i>=<i>sql-expression-2</i>,                          ...&gt;
			&lt;<i>column-1</i>=<i>sql-expression-1</i>&lt;, <i>column-1</i>=<i>sql-expression-2</i>,                                ...&gt;&gt;
		&lt;WHERE <i>sql-expression</i>&gt;;

	VALIDATE <i>query-expression</i>;
&lt;QUIT ;&gt;To connect to a DBMS and send it a DBMS-specific nonquery SQL statement, use this form: PROC SQL ;
	CONNECT TO <i>dbms-name</i>&lt;AS <i>alias</i>&gt;
		&lt;(<i>connect-statement-argument-1=value-1</i> 
		&lt;<i>connect-statement-argument-2=value-2</i> ...&gt;)&gt;
		&lt;(<i>database-connection-argument-1=value-1</i> 
		&lt;<i>database-connection-argument-2=value-2</i> ...&gt;)&gt;;

	EXECUTE  (<i>dbms-SQL-statement</i>) 
		BY <i>dbms-name</i> | <i>alias</i>;

	&lt;DISCONNECT FROM <i>dbms-name</i> | <i>alias</i>;&gt;&lt;QUIT ;&gt;To connect to a DBMS and query the DBMS data, use this form:PROC SQL ;
	CONNECT TO <i>dbms-name</i>&lt;AS <i>alias</i>&gt;
		&lt;(<i>connect-statement-argument-1=value-1</i> 
		&lt;<i>connect-statement-argument-2=value-2</i> ...&gt;)&gt;
		&lt;(<i>database-connection-argument-1=value-1</i> 
		&lt;<i>database-connection-argument-2=value-2</i> ...&gt;)&gt;;

	SELECT <i>column-list</i>
		FROM  CONNECTION TO <i>dbms-name | alias</i>
			 (<i>dbms-query</i>)
			<i>optional PROC SQL clauses</i>;

	&lt;DISCONNECT FROM <i>dbms-name</i> | <i>alias</i>;&gt;&lt;QUIT ;&gt;

ALTER TABLE <i>table-name</i>
	&lt;ADD  <i>column-definition-1</i>&lt;, <i>column-definition-2</i>,  ...&gt;&gt;

	&lt;ADD  <i>constraint-specification-1</i>&lt;, <i>constraint-specification-2</i>,  ...&gt;&gt;

	&lt;ADD CONSTRAINT <i>constraint-name-1</i> <i>constraint-specification-1</i>&lt;, <i>constraint-name-2</i><i>constraint-specification-2</i>,  ...&gt;
		&gt;

	&lt;DROP <i>column-1</i>&lt;, <i>column-2</i>,  ...&gt;&gt;

	&lt;DROP CONSTRAINT <i>constraint-name-1</i>&lt;, <i>constraint-name-2</i>,  ...&gt;&gt;

	&lt;DROP FOREIGN KEY <i>constraint-name</i>&gt;

	&lt;DROP PRIMARY KEY &gt;

	&lt;MODIFY <i>column-definition-1</i>&lt;, <i>column-definition-2</i>,  ...&gt;&gt;
                                       ;

INSERT INTO <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>
&lt;(<i>column-1</i>&lt;, <i>column-2</i>,  ...&gt;)&gt;
	SET <i>column1=</i><i>sql-expression-1</i>&lt;, <i>column-2=</i><i>sql-expression-2</i>,  ...&gt;
INSERT INTO <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>
&lt;(<i>column-1</i> &lt;, <i>column-2</i>,  ...&gt;)&gt;
	VALUES  (<i>value-1</i>&lt;, <i>value-2</i>,  ...&gt;) 
		&lt;VALUES  (<i>value-1</i>&lt;, <i>value-2</i>,  ...&gt;) &gt;;
INSERT INTO <i>table-name</i> | <i>sas/access-view</i> | <i>proc-sql-view</i>
&lt;(<i>column-1</i>&lt;, <i>column-2</i>,  ...&gt;)&gt;
<i>query-expression</i>;

SELECT &lt;DISTINCT | UNIQUE&gt;<i>object-item-1</i>&lt;, <i>object-item-2</i>,  ...&gt;

		&lt;INTO <i>macro-variable-specification-1</i>&lt;, <i>macro-variable-specification-2</i>,  ...&gt;&gt;
		FROM <i>from-list</i>
		&lt;WHERE <i>sql-expression</i>&gt;
		&lt;GROUP BY <i>group-by-item-1</i>&lt;, <i>group-by-item-2</i>,  ...&gt;&gt;
		&lt;HAVING <i>sql-expression</i>&gt;
		&lt;ORDER BY <i>order-by-item-1</i>&lt;, <i> order-by-item-2</i> &lt;ASC | DESC&gt;,  ...&gt;&gt;;
